BasicProperties.ActionCode:
if (radio.getValue() == 0){
	uI_Results.v_selectedChartText = "de belastingduurkromme";
	gr_year.setVisible(true);
	gr_details.setVisible(false);
	gr_heatmap.setVisible(false);
}
else if( radio.getValue() == 1){
	uI_Results.v_selectedChartText = "de belastingduurkrommes";
	gr_year.setVisible(false);
	gr_details.setVisible(true);
	gr_heatmap.setVisible(false);
}
else {
	f_makeHeatmapTrafo();
	uI_Results.v_selectedChartText = "de heatmaps";
	gr_heatmap.setVisible(true);
	gr_year.setVisible(false);
	gr_details.setVisible(false);
}

RoundedRectangle.OnClickCode:
if( gr_heatmap.isVisible() ){
	gr_heatmap.setVisible(false);
	uI_Results.v_selectedChartText = "de belastingduurkromme";
	gr_year.setVisible(true);
}
else{
	f_makeHeatmapTrafo();
	gr_heatmap.setVisible(true);
	uI_Results.v_selectedChartText = "de congestie heatmap";
	gr_year.setVisible(false);
}
